import{_ as a,o as r,c as i,ak as t}from"./chunks/framework.B_unCYUt.js";const m=JSON.parse('{"title":"软件工程","description":"","frontmatter":{"内容描述":"编程技术, 软件技术, 编程思想"},"headers":[],"relativePath":"软件工程.md","filePath":"软件工程.md","lastUpdated":1776174046000}'),n={name:"软件工程.md"};function s(o,e,l,h,d,p){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="软件工程" tabindex="-1">软件工程 <a class="header-anchor" href="#软件工程" aria-label="Permalink to “软件工程”">​</a></h1><blockquote><p>参考上海交大中的内容</p></blockquote><p>software engineering</p><p><code>如何开始一个新项目</code></p><h1 id="上海交大软件工程" tabindex="-1"><strong>上海交大软件工程</strong> <a class="header-anchor" href="#上海交大软件工程" aria-label="Permalink to “上海交大软件工程”">​</a></h1><p><a href="./软件工程.html">软件工程</a></p><h1 id="结构化设计" tabindex="-1">结构化设计 <a class="header-anchor" href="#结构化设计" aria-label="Permalink to “结构化设计”">​</a></h1><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to “参考资料”">​</a></h2><h2 id="_1974-structured-design" tabindex="-1">1974-structured-design <a class="header-anchor" href="#_1974-structured-design" aria-label="Permalink to “1974-structured-design”">​</a></h2><p>Considerations and techniques are proposed that reduce the complexity ofprograms by dividing them into functional modules. This can make it possible to create complex systems from simple, independent, reusable modules. Debugging and modifying pro- grams, reconfiguring I/O devices, and managing large program- ming projects can all be greatly simplified. And, as the module library grows, increasingly sophisticated programs can be im- plemented using less and less new code.</p><blockquote><p>Structured design by W. P. Stevens, G. J. Myers, and L. L. Constantine</p></blockquote><p>Structured design is a set of proposed general program design considerations and techniques for making coding, debugging, and modification easier, faster, and less expensive by reducing complexity.I The major ideas are the result of nearly ten years of research by Mr. Constantine.&#39; His results are presented here, but the authors do not intend to present the theory and derivation of the results in this paper. These ideas have been called compos- ite design by Mr. Myers.3-5 The authors believe these program design techniques are compatible with, and enhance, the docu- mentation techniques of H1P06 and the coding techniques of structured programming.&quot;</p><p>These cost-saving techniques always need to be balanced with other constraints on the system. But the ability to produce sim- ple, changeable programs will become increasingly important as the cost of the programmer&#39;s time continues to rise.</p><h2 id="结构化设计-个人翻译" tabindex="-1">结构化设计(个人翻译) <a class="header-anchor" href="#结构化设计-个人翻译" aria-label="Permalink to “结构化设计(个人翻译)”">​</a></h2><h1 id="技术选型" tabindex="-1">技术选型 <a class="header-anchor" href="#技术选型" aria-label="Permalink to “技术选型”">​</a></h1><h1 id="计算机中间件" tabindex="-1">计算机中间件 <a class="header-anchor" href="#计算机中间件" aria-label="Permalink to “计算机中间件”">​</a></h1><h1 id="通用概念" tabindex="-1">通用概念 <a class="header-anchor" href="#通用概念" aria-label="Permalink to “通用概念”">​</a></h1><h2 id="工程化" tabindex="-1">工程化 <a class="header-anchor" href="#工程化" aria-label="Permalink to “工程化”">​</a></h2><p>python</p><p>持续集成 CIJenkins / gitlab CI</p><p>配置管理: configuration management <em>ansible</em> salt</p><h2 id="使用功能" tabindex="-1">使用功能 <a class="header-anchor" href="#使用功能" aria-label="Permalink to “使用功能”">​</a></h2><p>工具版本控制:</p><p>自动补全:</p><p>虚拟环境:</p><p>编写测试:</p><p>使用: SQL /NoSQL</p><p>调试器: debugger</p><p>运行和调试:</p><p>远程代码代码重构: refactorissue trackers</p><p>错误提示: code linting</p><p>类型提示: type hintings</p><p>持续集成工具: continuous integrations</p><p>代码覆盖: code coverage</p><p>代码分析器: python profiler</p><h2 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to “测试”">​</a></h2><blockquote><p>开发人员通常只做单元测试, 集成测试则一般交由专门的测试工程师完成</p></blockquote><p>单元测试 :单向功能测试, 在单独模块测试</p><p>集成测试 : 集成到生产环境, 整合代码时, 集成测试</p><p>测试函数单元, 功能单元, 模块单元</p><p><em>编写单元测试</em>的习惯</p><p>重要性:</p><ul><li>保证研发质量</li><li>提高项目的稳定性</li><li>提高开发速度</li></ul><h3 id="单元测试" tabindex="-1">单元测试 <a class="header-anchor" href="#单元测试" aria-label="Permalink to “单元测试”">​</a></h3><p>测试函数单元, 功能单元, 模块单元</p><p><em>编写单元测试</em>的习惯</p><p>重要性:</p><ul><li>保证研发质量</li><li>提高项目的稳定性</li><li>提高开发速度</li></ul><h1 id="权限控制" tabindex="-1">权限控制 <a class="header-anchor" href="#权限控制" aria-label="Permalink to “权限控制”">​</a></h1><blockquote><p>权限控制的粒度</p></blockquote><p><strong>赋能（Enable）</strong>：这个词所传达的核心意思，是怎样让别人有更大的能力去完成他们想要完成的事情。</p><p>后端 对象权限控制</p><h2 id="前端权限控制" tabindex="-1">前端权限控制 <a class="header-anchor" href="#前端权限控制" aria-label="Permalink to “前端权限控制”">​</a></h2><ul><li>登录权限</li><li>页面权限</li><li>接口权限</li><li>功能权限</li></ul><h1 id="测试用例" tabindex="-1">测试用例 <a class="header-anchor" href="#测试用例" aria-label="Permalink to “测试用例”">​</a></h1><p>测试用例(Test Case)是指对一项特定的软件产品进行测试任务的描述，体现测试方案、方法、技术和策略。其内容包括测试目标、测试环境、输入数据、<strong>测试步骤</strong>、<strong>预期结果</strong>、测试脚本等，最终形成文档。简单地认为，测试用例是为某个特殊目标而编制的一组测试输入、执行条件以及预期结果，用于核实是否满足某个特定软件需求。</p><h1 id="软件架构" tabindex="-1">软件架构 <a class="header-anchor" href="#软件架构" aria-label="Permalink to “软件架构”">​</a></h1><h3 id="sidecar-pattern-旁车模式" tabindex="-1">sidecar pattern(旁车模式) <a class="header-anchor" href="#sidecar-pattern-旁车模式" aria-label="Permalink to “sidecar pattern(旁车模式)”">​</a></h3><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/20260130172056541.png" alt="img"></p><h1 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to “项目结构”">​</a></h1><p>project structure</p><p>sidecar 多项目时, 向web这些 应该允许一些项目的 root 在子目录中, 没必要都让 root directory 设在根目录</p><h1 id="devops" tabindex="-1">DevOps <a class="header-anchor" href="#devops" aria-label="Permalink to “DevOps”">​</a></h1><p>持续交付</p><p>代码质量, 工程化, 流程化</p><h1 id="serverless" tabindex="-1">Serverless <a class="header-anchor" href="#serverless" aria-label="Permalink to “Serverless”">​</a></h1><h1 id="容器技术" tabindex="-1">容器技术 <a class="header-anchor" href="#容器技术" aria-label="Permalink to “容器技术”">​</a></h1><h1 id="graphql" tabindex="-1">GraphQL <a class="header-anchor" href="#graphql" aria-label="Permalink to “GraphQL”">​</a></h1>',68)])])}const b=a(n,[["render",s]]);export{m as __pageData,b as default};
